using UnityEngine;
using Cinemachine;

/// <summary>
/// CameraManager — efeitos de seguimento do player (Tarefa #21):
/// look up (olhar pra cima ao ficar parado), zoom dinâmico por velocidade,
/// offset/facing e lookahead horizontal. Aplica-se às 3 vcams automáticas
/// (Normal/Corridor/Boss) em <see cref="CameraManager.Update"/>.
/// </summary>
public partial class CameraManager
{
    [Header("Look Up (Exploration)")]
    [Tooltip("Tempo segurando 'cima' para activar olhar pra cima.")]
    [SerializeField] private float lookUpHoldDelay = 1.5f;

    [Tooltip("Quanto a camera sobe quando activa olhar pra cima.")]
    [SerializeField] private float lookUpAmount = 2.0f;

    [SerializeField] private float lookUpSmoothTime = 0.15f;

    [Tooltip("Só activa look up se estiver praticamente parado (velocidade X)")]
    [SerializeField] private float lookUpRestSpeedThreshold = 0.15f;

    [Header("Dynamic Zoom (by speed)")]
    [SerializeField] private bool enableDynamicZoom = true;
    [SerializeField] private float zoomIdle = 5.8f;
    [SerializeField] private float zoomRun = 6.6f;
    [SerializeField] private float speedForMaxZoom = 10.5f;
    [SerializeField] private float zoomSmoothTime = 0.20f;

    [Header("Offset / Facing")]
    [SerializeField] private float baseOffsetX = 1.4f;
    [SerializeField] private float baseOffsetY = -0.6f;

    [Header("Lookahead (horizontal only)")]
    [SerializeField] private float lookaheadTime = 0.15f;
    [SerializeField] private float lookaheadSmoothing = 8f;

    // Look up state
    private float lookUpHoldTimer = 0f;
    private float lookUpCurrent = 0f;
    private float lookUpVel = 0f;

    // Zoom smoothing (separado por vcam)
    private float zoomVelNormal = 0f;
    private float zoomVelCorridor = 0f;
    private float zoomVelBoss = 0f;

    private void UpdateLookUpHold()
    {
        // regra: só olha pra cima se estiver no chão e parado
        bool grounded = playerMotor != null && playerMotor.IsGrounded;
        bool stopped = playerRb != null && Mathf.Abs(playerRb.velocity.x) <= lookUpRestSpeedThreshold;

        Vector2 move = GetMoveInput();
        bool upHeld = move.y > 0.5f;

        if (grounded && stopped && upHeld)
            lookUpHoldTimer += Time.deltaTime;
        else
            lookUpHoldTimer = 0f;

        float target = (lookUpHoldTimer >= lookUpHoldDelay) ? lookUpAmount : 0f;
        lookUpCurrent = Mathf.SmoothDamp(lookUpCurrent, target, ref lookUpVel, lookUpSmoothTime);
    }

    private void UpdateAutoCameraParams()
    {
        ApplyParamsToAuto(vcamNormal);
        ApplyParamsToAuto(vcamCorridor);
        ApplyParamsToAuto(vcamBoss);
    }

    private void ApplyParamsToAuto(CinemachineVirtualCamera vcam)
    {
        if (vcam == null) return;

        var transposer = vcam.GetCinemachineComponent<CinemachineFramingTransposer>();
        if (transposer != null)
        {
            float ox = baseOffsetX * facingSign;
            float oy = baseOffsetY + lookUpCurrent;

            transposer.m_TrackedObjectOffset = new Vector3(ox, oy, 0f);

            transposer.m_LookaheadTime = lookaheadTime;
            transposer.m_LookaheadSmoothing = lookaheadSmoothing;
            transposer.m_LookaheadIgnoreY = true;
        }
    }

    private void UpdateDynamicZoom()
    {
        if (playerRb == null) return;

        float speed = Mathf.Abs(playerRb.velocity.x);
        float t = Mathf.Clamp01(speed / Mathf.Max(0.01f, speedForMaxZoom));
        float desired = Mathf.Lerp(zoomIdle, zoomRun, t);

        ApplyZoomToAuto(vcamNormal, desired, ref zoomVelNormal);
        ApplyZoomToAuto(vcamCorridor, desired, ref zoomVelCorridor);
        ApplyZoomToAuto(vcamBoss, desired, ref zoomVelBoss);
    }

    private void ApplyZoomToAuto(CinemachineVirtualCamera vcam, float desired, ref float vel)
    {
        if (vcam == null) return;
        float current = vcam.m_Lens.OrthographicSize;
        float next = Mathf.SmoothDamp(current, desired, ref vel, zoomSmoothTime);
        vcam.m_Lens.OrthographicSize = next;
    }
}
